import time
import random
from enum import Enum

class NetworkStatus(Enum):
 CONNECTED = "connected"
 PARTITIONED = "partitioned"

class CPDatabase:
 """CP System - Prioritizes Consistency over Availability."""

 def __init__(self):
 self.data = {}
 self.network_status = NetworkStatus.CONNECTED
 self.replicas = [{}, {}] # Two replica nodes

 def write(self, key, value):
 """Write requires consensus from all replicas."""
 if self.network_status == NetworkStatus.PARTITIONED:
 # CP: Reject write to maintain consistency
 raise Exception("UNAVAILABLE: Cannot guarantee consistency during partition")

 # Normal operation: Write to all replicas
 self.data[key] = value
 for replica in self.replicas:
 replica[key] = value
 return f"Write successful: {key}={value}"

 def read(self, key):
 """Read requires confirmation from majority."""
 if self.network_status == NetworkStatus.PARTITIONED:
 # CP: Return error rather than potentially stale data
 raise Exception("UNAVAILABLE: Cannot guarantee consistency during partition")

 return self.data.get(key, None)

 def simulate_partition(self):
 """Simulate network partition."""
 self.network_status = NetworkStatus.PARTITIONED
 print("NETWORK PARTITION OCCURRED!")

 def heal_partition(self):
 """Heal network partition."""
 self.network_status = NetworkStatus.CONNECTED
 print("Network partition healed")

# Demo CP System
print("=== CP System Demo ===")
cp_db = CPDatabase()

# Normal operation
print(cp_db.write("user:1", "Alice"))
print(f"Read: {cp_db.read('user:1')}")

# During partition
cp_db.simulate_partition()
try:
 cp_db.write("user:2", "Bob") # This will fail
except Exception as e:
 print(f"Write failed: {e}")

try:
 cp_db.read("user:1") # This will also fail
except Exception as e:
 print(f"Read failed: {e}")

from enum import Enum
import random

class ConsistencyLevel(Enum):
 ONE = 1 # Single node response
 QUORUM = 2 # Majority response
 ALL = 3 # All nodes respond

class TunableDatabase:
 """Database with tunable consistency (like Cassandra)."""

 def __init__(self, num_replicas=3):
 self.num_replicas = num_replicas
 self.replicas = [{} for _ in range(num_replicas)]
 self.alive_replicas = list(range(num_replicas))

 def quorum_size(self):
 return (self.num_replicas // 2) + 1

 def write(self, key, value, consistency=ConsistencyLevel.QUORUM):
 """Write with specified consistency level."""
 required = self._get_required_acks(consistency)
 acks = 0

 for i in self.alive_replicas:
 self.replicas[i][key] = value
 acks += 1
 if acks >= required:
 return f"Write {key}={value} with {consistency.name} (acks: {acks}/{required})"

 if acks < required:
 raise Exception(f"UNAVAILABLE: Only {acks}/{required} acks received")

 def read(self, key, consistency=ConsistencyLevel.QUORUM):
 """Read with specified consistency level."""
 required = self._get_required_acks(consistency)
 responses = []

 for i in self.alive_replicas:
 if key in self.replicas[i]:
 responses.append(self.replicas[i][key])
 if len(responses) >= required:
 break

 if len(responses) < required:
 raise Exception(f"UNAVAILABLE: Only {len(responses)}/{required} responses")

 # Return most recent (or resolve conflict)
 return responses[0]

 def _get_required_acks(self, consistency):
 if consistency == ConsistencyLevel.ONE:
 return 1
 elif consistency == ConsistencyLevel.QUORUM:
 return self.quorum_size()
 else: # ALL
 return self.num_replicas

 def fail_replica(self, replica_id):
 """Simulate replica failure."""
 if replica_id in self.alive_replicas:
 self.alive_replicas.remove(replica_id)
 print(f"Replica {replica_id} failed. Alive: {self.alive_replicas}")

# Demo Tunable Consistency
print("=== Tunable Consistency Demo ===")
db = TunableDatabase(num_replicas=3)

print("\n--- All replicas healthy ---")
print(db.write("x", 100, ConsistencyLevel.ALL))
print(db.write("y", 200, ConsistencyLevel.QUORUM))
print(db.write("z", 300, ConsistencyLevel.ONE))

print("\n--- One replica fails ---")
db.fail_replica(2)

try:
 print(db.write("a", 400, ConsistencyLevel.ALL)) # Fails - needs all 3
except Exception as e:
 print(f"ALL consistency: {e}")

print(db.write("a", 400, ConsistencyLevel.QUORUM)) # Works - needs 2
print(db.write("b", 500, ConsistencyLevel.ONE)) # Works - needs 1
